import { useEffect, useState } from "react";
import axios from "axios";

const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:8000";

export default function Menu() {
  const [foods, setFoods] = useState([]);
  const [activeCategory, setActiveCategory] = useState("all");

  useEffect(() => {
    fetchFoods();
  }, []);

  const fetchFoods = async () => {
    try {
      const res = await axios.get(`${API_BASE}/api/food/`);
      setFoods(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const categories = [
    "all",
    "bread",
    "drinks",
    "veg",
    "non-veg",
    "dessert",
  ];

  const filteredFoods =
    activeCategory === "all"
      ? foods
      : foods.filter((f) => f.category === activeCategory);

  return (
    <div className="menu-page">
      <style>{`
        /* ================================
   GUEST MENU – LUXURY IVORY THEME
   ================================ */

.menu-page {
  background: #f8f4ec; /* Ivory */
  min-height: 100vh;
  padding: 80px 24px;
  color: #2a2a2a;
  font-family: 'Montserrat', 'Segoe UI', sans-serif;
}

/* ---------- HEADER ---------- */

.menu-header {
  text-align: center;
  margin-bottom: 50px;
}

.menu-header h1 {
  color: #c89d5c; /* Gold accent */
  font-size: 42px;
  margin-bottom: 10px;
  font-weight: 600;
}

.menu-header p {
  color: #555;
  font-size: 15px;
  letter-spacing: 0.4px;
}

/* ---------- CATEGORY TABS ---------- */

.category-tabs {
  display: flex;
  justify-content: center;
  gap: 16px;
  flex-wrap: wrap;
  margin-bottom: 40px;
}

.category-tabs button {
  background: transparent;
  border: 1px solid #c89d5c;
  color: #7a5a2b;
  padding: 8px 20px;
  border-radius: 20px;
  cursor: pointer;
  font-size: 13px;
  letter-spacing: 0.8px;
  transition: all 0.25s ease;
}

.category-tabs button:hover {
  background: rgba(200, 157, 92, 0.15);
}

.category-tabs button.active {
  background: #c89d5c;
  color: #111;
}

/* ---------- MENU GRID ---------- */

.menu-grid {
  max-width: 1200px;
  margin: auto;
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
  gap: 26px;
}

/* ---------- MENU CARD ---------- */

.menu-card {
  background: rgba(255, 255, 255, 0.78);
  backdrop-filter: blur(12px);
  border-radius: 18px;
  overflow: hidden;
  border: 1px solid rgba(200, 157, 92, 0.25);
  transition: transform 0.25s ease, box-shadow 0.25s ease;
}

.menu-card:hover {
  transform: translateY(-6px);
  box-shadow: 0 18px 40px rgba(0, 0, 0, 0.12);
}

/* ---------- IMAGE ---------- */

.menu-card img {
  width: 100%;
  height: 190px;
  object-fit: cover;
}

/* ---------- CONTENT ---------- */

.menu-content {
  padding: 18px;
}

.menu-content .category {
  font-size: 12px;
  text-transform: uppercase;
  color: #c89d5c;
  margin-bottom: 8px;
  letter-spacing: 1px;
}

.menu-content h3 {
  font-size: 18px;
  color: #2a2a2a;
  margin-bottom: 6px;
  font-weight: 500;
}

.menu-content .price {
  font-size: 16px;
  font-weight: 600;
  color: #7a5a2b;
}

/* ---------- EMPTY STATE ---------- */

.menu-grid p {
  grid-column: 1 / -1;
  text-align: center;
  color: #777;
  font-size: 14px;
}

/* ---------- RESPONSIVE ---------- */

@media (max-width: 768px) {
  .menu-header h1 {
    font-size: 34px;
  }

  .menu-page {
    padding: 60px 16px;
  }
}

@media (max-width: 480px) {
  .menu-header h1 {
    font-size: 30px;
  }

  .menu-content h3 {
    font-size: 16px;
  }
}

      `}</style>

      <div className="menu-header">
        <h1>Our Menu</h1>
        <p>Carefully crafted dishes for your perfect stay</p>
      </div>

      <div className="category-tabs">
        {categories.map((cat) => (
          <button
            key={cat}
            className={activeCategory === cat ? "active" : ""}
            onClick={() => setActiveCategory(cat)}
          >
            {cat.toUpperCase()}
          </button>
        ))}
      </div>

      <div className="menu-grid">
        {filteredFoods.length === 0 ? (
          <p style={{ textAlign: "center", gridColumn: "1/-1" }}>
            No items available
          </p>
        ) : (
          filteredFoods.map((food) => (
            <div className="menu-card" key={food.id}>
              <img
                src={food.image_url || `${API_BASE}${food.image}`}
                alt={food.name}
              />
              <div className="menu-content">
                <div className="category">{food.category}</div>
                <h3>{food.name}</h3>
                <div className="price">₹{food.price}</div>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}
